import os
import json
import shutil
from pathlib import Path
from typing import Optional, Dict, Any, List, Tuple
import yaml
import re


class VersionManager:
    """Manages non-destructive overlay versions for config-driven features.

    - Overlays live under versions/<id>/overlay.yaml with meta.json
    - Test mode applies overlay in-memory and can be dropped to restore baseline
    - Promote merges overlay into stable config.yaml with backup
    """

    def __init__(self, base_dir: str = "versions"):
        self.base_dir = Path(base_dir)
        self.base_dir.mkdir(parents=True, exist_ok=True)
        self.active_id: Optional[str] = None
        self._baseline: Optional[Dict[str, Any]] = None
        self._metrics: Dict[str, Any] = {"requests": 0, "errors": 0, "durations": []}
        # Full-version pointers
        self.stable_ptr = self.base_dir / 'STABLE'
        self.active_test_ptr = self.base_dir / 'ACTIVE_TEST'

    def list_overlays(self) -> List[Dict[str, Any]]:
        items = []
        for p in sorted(self.base_dir.iterdir() if self.base_dir.exists() else [], key=lambda x: x.name):
            if not p.is_dir():
                continue
            meta = {}
            try:
                with open(p / 'meta.json', 'r') as f:
                    meta = json.load(f)
            except Exception:
                meta = {"id": p.name}
            items.append({"id": p.name, **meta})
        return items

    def overlay_path(self, overlay_id: str) -> Path:
        return self.base_dir / overlay_id

    def load_overlay(self, overlay_id: str) -> Dict[str, Any]:
        path = self.overlay_path(overlay_id) / 'overlay.yaml'
        if not path.exists():
            raise FileNotFoundError(f"Overlay not found: {overlay_id}")
        with open(path, 'r') as f:
            return yaml.safe_load(f) or {}

    def preview_overlay(self, overlay_id: str) -> Dict[str, Any]:
        return self.load_overlay(overlay_id)

    def _config_to_dict(self, cfg) -> Dict[str, Any]:
        # Prefer Config.to_dict if present
        if hasattr(cfg, 'to_dict') and callable(getattr(cfg, 'to_dict')):
            return cfg.to_dict()
        # Fallback via save to a temporary file then load
        tmp_dir = self.base_dir / '.tmp'
        tmp_dir.mkdir(exist_ok=True)
        tmp_file = tmp_dir / 'baseline.yaml'
        try:
            cfg.save(str(tmp_file))
            with open(tmp_file, 'r') as f:
                return yaml.safe_load(f) or {}
        finally:
            try:
                tmp_file.unlink(missing_ok=True)
            except Exception:
                pass

    def apply_overlay(self, cfg, overlay: Dict[str, Any]):
        # Merge known categories into cfg
        for cat in ['routing', 'optimization', 'policy', 'interface', 'history', 'runtime']:
            data = overlay.get(cat)
            if not data:
                continue
            obj = getattr(cfg, cat, None)
            if not obj:
                continue
            for k, v in data.items():
                if hasattr(obj, k):
                    setattr(obj, k, v)

    def test_overlay(self, overlay_id: str, cfg, recreate: callable):
        if self.active_id:
            raise RuntimeError("Another overlay is already active")
        self._baseline = self._config_to_dict(cfg)
        ov = self.load_overlay(overlay_id)
        self.apply_overlay(cfg, ov)
        self.active_id = overlay_id
        self._metrics = {"requests": 0, "errors": 0, "durations": []}
        # Callback to recreate components (e.g., router/policy) against new cfg
        try:
            recreate()
        except Exception:
            pass

    def end_test(self, cfg, recreate: callable):
        if not self.active_id:
            return
        # Restore baseline cfg
        baseline = self._baseline or {}
        try:
            # Use Config.from_dict to rebuild
            cfg_new = cfg.from_dict(baseline)
            # Copy fields back into existing cfg instance
            for field, value in baseline.items():
                if hasattr(cfg, field):
                    setattr(cfg, field, getattr(cfg_new, field))
        except Exception:
            pass
        # Recreate components
        try:
            recreate()
        except Exception:
            pass
        self.write_metrics(self.active_id)
        self.active_id = None
        self._baseline = None

    def record_metric(self, duration: float, error: bool = False):
        if not self.active_id:
            return
        self._metrics["requests"] += 1
        if error:
            self._metrics["errors"] += 1
        self._metrics["durations"].append(duration)

    def write_metrics(self, overlay_id: str):
        try:
            out = self.overlay_path(overlay_id) / 'metrics.json'
            with open(out, 'w') as f:
                json.dump(self._metrics, f, indent=2)
        except Exception:
            pass

    def save_current_as_overlay(self, cfg, note: str = "") -> str:
        # Create new overlay id
        import time
        overlay_id = time.strftime('%Y%m%d_%H%M%S')
        path = self.overlay_path(overlay_id)
        path.mkdir(parents=True, exist_ok=True)
        # Save overlay.yaml with selected categories
        data = self._config_to_dict(cfg)
        overlay = {k: data.get(k, {}) for k in ['routing', 'optimization', 'policy']}
        with open(path / 'overlay.yaml', 'w') as f:
            yaml.safe_dump(overlay, f, sort_keys=False)
        meta = {"id": overlay_id, "note": note}
        with open(path / 'meta.json', 'w') as f:
            json.dump(meta, f, indent=2)
        return overlay_id

    def delete_overlay(self, overlay_id: str):
        path = self.overlay_path(overlay_id)
        if path.exists():
            shutil.rmtree(path)

    def promote_overlay(self, overlay_id: str, stable_config_path: str):
        # Backup
        stable = Path(stable_config_path)
        if not stable.exists():
            raise FileNotFoundError(f"Config file not found: {stable}")
        shutil.copy2(stable, stable.with_suffix(stable.suffix + '.bak'))
        # Merge overlay into stable file
        with open(stable, 'r') as f:
            base = yaml.safe_load(f) or {}
        overlay = self.load_overlay(overlay_id)
        for cat in ['routing', 'optimization', 'policy']:
            if cat in overlay:
                base.setdefault(cat, {})
                base[cat].update(overlay[cat] or {})
        with open(stable, 'w') as f:
            yaml.safe_dump(base, f, sort_keys=False)

    # ===== Full Version Management (directory-based) =====
    def list_versions(self) -> List[str]:
        labels: List[str] = []
        if not self.base_dir.exists():
            return labels
        for p in sorted(self.base_dir.iterdir(), key=lambda x: x.name):
            if not p.is_dir():
                continue
            # Skip internal dirs for overlays (identified by overlay.yaml)
            # Accept versions that contain a site-packages path
            if (p / 'site-packages').exists():
                labels.append(p.name)
        return labels

    def list_versions_with_status(self) -> List[Dict[str, Any]]:
        """Return all version dirs with completion and validity status."""
        items: List[Dict[str, Any]] = []
        if not self.base_dir.exists():
            return items
        for p in sorted(self.base_dir.iterdir(), key=lambda x: x.name):
            if not p.is_dir():
                continue
            if p.name in {'.tmp'}:
                continue
            complete = (p / 'site-packages').exists()
            valid = False
            man = p / 'manifest.json'
            if man.exists():
                try:
                    import json
                    with open(man, 'r') as f:
                        data = json.load(f)
                    valid = bool(data.get('valid', False))
                except Exception:
                    valid = False
            items.append({'label': p.name, 'complete': complete, 'valid': valid, 'path': str(p)})
        return items

    def _atomic_write(self, path: Path, content: str):
        tmp = path.with_suffix(path.suffix + '.tmp')
        with open(tmp, 'w') as f:
            f.write(content)
        tmp.replace(path)

    def get_stable(self) -> Optional[str]:
        try:
            return self.stable_ptr.read_text().strip()
        except Exception:
            return None

    def set_stable(self, label: str):
        self._atomic_write(self.stable_ptr, label)

    def get_active_test(self) -> Optional[str]:
        try:
            return self.active_test_ptr.read_text().strip()
        except Exception:
            return None

    def set_active_test(self, label: str):
        self._atomic_write(self.active_test_ptr, label)

    def clear_active_test(self):
        try:
            if self.active_test_ptr.exists():
                self.active_test_ptr.unlink()
        except Exception:
            pass

    def validate_version(self, label: str, source_label: Optional[str] = None) -> Tuple[bool, List[str]]:
        """Validate a version directory, write manifest, return status."""
        errors: List[str] = []
        vdir = self.base_dir / label
        if not vdir.exists():
            return False, [f"Version '{label}' not found"]
        if not (vdir / 'site-packages').exists():
            errors.append("Missing site-packages directory")
        # Config can be either versions/<label>/config.yaml or versions/<label>/config/config.yaml
        cfg1 = vdir / 'config.yaml'
        cfg2 = vdir / 'config' / 'config.yaml'
        if not (cfg1.exists() or cfg2.exists()):
            errors.append("Missing config.yaml (root or config/config.yaml)")

        # Check for per-version Launcher
        launcher_file = vdir / 'Launcher'
        if not launcher_file.exists():
            errors.append("Missing per-version Launcher script")
        elif not launcher_file.is_file() or not (launcher_file.stat().st_mode & 0o100):
            errors.append("Launcher script not executable")

        # Compile probe
        try:
            import py_compile
            for py in (vdir / 'site-packages').rglob('*.py'):
                try:
                    py_compile.compile(str(py), doraise=True)
                except Exception as e:
                    errors.append(f"Compile failed: {py}: {e}")
                    break
        except Exception as e:
            errors.append(f"Compilation error: {e}")

        # Import probe
        try:
            import subprocess, sys
            env = os.environ.copy()
            env['PYTHONPATH'] = str((vdir / 'site-packages').resolve())
            # Short probe to ensure import works
            proc = subprocess.run([sys.executable, '-c', 'import opencode; print("ok")'],
                                  capture_output=True, text=True, env=env, timeout=10)
            if proc.returncode != 0 or 'ok' not in proc.stdout:
                errors.append(f"Import probe failed: {proc.stderr.strip() or proc.stdout.strip()}")
        except Exception as e:
            errors.append(f"Import probe error: {e}")
        # Write manifest
        try:
            import json, time
            manifest = {
                'label': label,
                'source_label': source_label,
                'timestamp': int(time.time()),
                'valid': len(errors) == 0,
                'errors': errors,
            }
            with open((vdir / 'manifest.json'), 'w') as f:
                json.dump(manifest, f, indent=2)
        except Exception:
            pass

        return (len(errors) == 0), errors

    def get_current(self) -> Optional[str]:
        """Current running version (from environment)."""
        try:
            cur = os.environ.get('OPENCODE_VERSION', '').strip()
            return cur or None
        except Exception:
            return None

    def _sanitize_label(self, label: str) -> str:
        if not re.match(r'^[A-Za-z0-9_.:-]+$', label):
            raise ValueError("Invalid label: use letters, numbers, dashes, underscores, dots")
        return label

    def _auto_label(self, existing: List[str]) -> str:
        # Find next vN or vN.M
        max_major = 0
        max_minor = -1
        for lb in existing:
            m = re.match(r'^v(\d+)(?:\.(\d+))?$', lb)
            if not m:
                continue
            maj = int(m.group(1))
            mino = int(m.group(2)) if m.group(2) else -1
            if (maj > max_major) or (maj == max_major and mino > max_minor):
                max_major, max_minor = maj, mino
        if max_major == 0 and max_minor == -1:
            return 'v1'
        if max_minor >= 0:
            return f'v{max_major}.{max_minor+1}'
        return f'v{max_major+1}'

    def create_version(self, label: Optional[str] = None, from_label: Optional[str] = None) -> Tuple[str, str]:
        """Create a new version directory by copying from a source.

        Returns: (label, path)
        """
        labels = self.list_versions_with_status()
        existing = [it['label'] for it in labels]
        if not label:
            label = self._auto_label(existing)
        label = self._sanitize_label(label)
        vdir = self.base_dir / label
        if vdir.exists():
            raise FileExistsError(f"Version already exists: {label}")

        # Resolve source directory (prefer STABLE, then CURRENT, then explicit entry, then root)
        src_dir: Optional[Path] = None
        source_label: Optional[str] = None
        if from_label:
            key = from_label.lower()
            if key == 'stable':
                s = self.get_stable()
                if s:
                    src_dir = self.base_dir / s
                    source_label = s
            elif key == 'current':
                c = self.get_current()
                if c:
                    src_dir = self.base_dir / c
                    source_label = c
            else:
                candidate = self.base_dir / from_label
                if candidate.exists():
                    src_dir = candidate
                    source_label = from_label
        if not src_dir:
            s = self.get_stable()
            if s:
                src_dir = self.base_dir / s
                source_label = s
        if not src_dir:
            c = self.get_current()
            if c:
                src_dir = self.base_dir / c
                source_label = c
        if not src_dir:
            src_dir = Path.cwd()
            if not source_label:
                source_label = 'root'

        vdir.mkdir(parents=True, exist_ok=False)

        def _copy_tree(src: Path, dst: Path, include: List[str]):
            for name in include:
                sp = src / name
                dp = dst / name
                if not sp.exists():
                    continue
                if sp.is_dir():
                    shutil.copytree(
                        sp,
                        dp,
                        dirs_exist_ok=True,
                        ignore=shutil.ignore_patterns('__pycache__', '*.pyc', 'logs', 'sessions', 'exports')
                    )
                else:
                    dp.parent.mkdir(parents=True, exist_ok=True)
                    shutil.copy2(sp, dp)

        includes = ['site-packages', 'config.yaml', 'config']
        _copy_tree(src_dir, vdir, includes)
        (vdir / 'logs').mkdir(exist_ok=True)

        # Create per-version Launcher
        try:
            project_root = self.base_dir.parent.resolve()
            launcher_path = vdir / 'Launcher'

            template = '''#!/bin/bash
set -euo pipefail

BASE_DIR="__BASE__"
ROOT_DIR="__ROOT__"
VERS_DIR="$ROOT_DIR/versions"
label="__LABEL__"

is_test=0
no_prompt=0
while [[ $# -gt 0 ]]; do
  case "$1" in
    --test) is_test=1; shift ;;
    --no-prompt) no_prompt=1; shift ;;
    --version) shift ;; # ignored; label is fixed for this launcher
    *) shift ;;
  esac
done

cd "$ROOT_DIR"

# Point to this version's code/config
export OPENCODE_VERSION="$label"
export OPENCODE_TEST="$is_test"
export PYTHONPATH="$BASE_DIR/site-packages"

CFG=
if [[ -f "$BASE_DIR/config.yaml" ]]; then
  CFG="$BASE_DIR/config.yaml"
elif [[ -f "$BASE_DIR/config/config.yaml" ]]; then
  CFG="$BASE_DIR/config/config.yaml"
fi

cmd=( python3 -m opencode -i )
if [[ -n "$CFG" ]]; then cmd+=( -c "$CFG" ); fi

start_ts=$(date +%s)
set +e
"${cmd[@]}" 2>> "$BASE_DIR/crash_log.txt"
status=$?
set -e
end_ts=$(date +%s)
runtime=$(( end_ts - start_ts ))

# Helper: relaunch STABLE via base launcher and clear ACTIVE_TEST
relaunch_stable() {
  if [[ -f "$VERS_DIR/ACTIVE_TEST" ]]; then rm -f "$VERS_DIR/ACTIVE_TEST"; fi
  if [[ -f "$VERS_DIR/STABLE" ]]; then
    local stable
    stable=$(cat "$VERS_DIR/STABLE" | tr -d '\\n\\r')
    if [[ -n "$stable" && -d "$VERS_DIR/$stable/site-packages" ]]; then
      exec "$ROOT_DIR/Launcher" --version "$stable" --no-prompt
    fi
  fi
}

if [[ $status -ne 0 || $runtime -lt 3 ]]; then
  relaunch_stable
elif [[ "$is_test" -eq 1 ]]; then
  relaunch_stable
fi

if [[ "$no_prompt" -ne 1 ]]; then
  read -p "Press Enter to close this window..."
fi
'''

            script = (
                template
                .replace("__BASE__", str(vdir.resolve()))
                .replace("__ROOT__", str(project_root))
                .replace("__LABEL__", label)
            )
            launcher_path.write_text(script)
            import os
            os.chmod(launcher_path, 0o755)
        except Exception as e:
            print(f"Warning: Failed to create per-version Launcher: {e}")

        try:
            if src_dir and src_dir.parent == self.base_dir:
                source_label = src_dir.name
            self.validate_version(label, source_label)
        except Exception:
            pass

        return label, str(vdir)

